const body = (typeof $json.body === 'object' && $json.body) ? $json.body : {};
const nestedBody = (typeof body.body === 'object' && body.body) ? body.body : {};
const now = new Date().toISOString();
const dossier_id = 'DOSSIER-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9).toUpperCase();
const route_id = $json.route_id || body.route_id || nestedBody.route_id || 'ROUTE_PHASE1_STANDARD';
const intake_topic = $json.topic || body.topic || nestedBody.topic || 'UNSPECIFIED_TOPIC';
const intake_packet = {
  instance_id: 'INTAKE-' + Date.now(),
  artifact_family: 'intake_packet',
  schema_version: '1.0.0',
  producer_workflow: 'WF-001',
  dossier_ref: dossier_id,
  created_at: now,
  status: 'CREATED',
  payload: {
    topic: intake_topic,
    route_selected: route_id
  }
};
return [{ json: { ...$json, dossier_id, route_id, intake_topic, intake_packet, created_at: now } }];

const dossier_id = $json.dossier_id;
const route_id = $json.route_id;
const now = new Date().toISOString();
const dossier = {
  dossier_id: dossier_id,
  route_id: route_id,
  current_workflow: 'WF-001',
  created_at: now,
  last_updated: now,
  status: 'INTAKE_INITIALIZED',
  namespaces: {
    system: {
      dossier_id: dossier_id,
      route_id: route_id,
      owner_workflow: 'WF-001',
      created_at: now,
      version: 1
    },
    intake: {
      topic: $json.intake_topic,
      intake_timestamp: now,
      intake_source: 'manual_user_input',
      intake_metadata: { user_mode: 'creator', selected_route: route_id },
      version: 1
    }
  }
};
return [{ json: { ...$json, dossier_record: dossier, intake_validation_ok: true } }];

try {
  const dossier = $json.dossier_record;
  if (!dossier || !dossier.dossier_id || !dossier.route_id || !dossier.namespaces?.system || !dossier.namespaces?.intake) {
    throw new Error('Dossier missing required fields: dossier_id, route_id, system namespace, or intake namespace');
  }
  const intakeTopic = dossier.namespaces.intake.topic;
  if (!intakeTopic || intakeTopic === 'UNSPECIFIED_TOPIC') {
    throw new Error('Intake topic not specified');
  }
  return [{ json: { ...$json, validation_status: 'SUCCESS', route_to_error: false } }];
} catch (error) {
  return [{ json: { ...$json, validation_status: 'FAILED', route_to_error: true, validation_error: String(error.message || error) } }];
}

if ($json.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const dossier = $json.dossier_record;
if (!dossier || !dossier.dossier_id) {
  throw new Error('WF-001 persistence failed: dossier_record missing dossier_id');
}

const repoRoot = 'C:/ShadowEmpire-Git';
const dossiersDir = path.join(repoRoot, 'dossiers');
const dataDir = path.join(repoRoot, 'data');
const dossierPath = path.join(dossiersDir, dossier.dossier_id + '.json');
const indexPath = path.join(dataDir, 'se_dossier_index.json');

if (!fs.existsSync(dossiersDir)) fs.mkdirSync(dossiersDir, { recursive: true });
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

const dossierToWrite = {
  ...dossier,
  _version: Number(dossier._version || 1),
  _created_at: dossier._created_at || dossier.created_at || now,
  _last_updated_at: now,
  _audit_trail: Array.isArray(dossier._audit_trail) ? dossier._audit_trail : [
    {
      timestamp: now,
      workflow_id: 'WF-001',
      operation: 'DOSSIER_CREATE',
      notes: 'Initial dossier created by WF-001'
    }
  ]
};
fs.writeFileSync(dossierPath, JSON.stringify(dossierToWrite, null, 2), 'utf8');

let index = {
  table: 'se_dossier_index',
  description: 'Index of all dossiers; updated by WF-001 and dossier_writer.',
  records: [],
  created_at: now,
  last_updated: now
};
if (fs.existsSync(indexPath)) {
  try {
    const parsed = JSON.parse(fs.readFileSync(indexPath, 'utf8'));
    index = {
      ...index,
      ...parsed,
      records: Array.isArray(parsed.records) ? parsed.records : []
    };
  } catch (e) {
    throw new Error('WF-001 persistence failed: se_dossier_index parse error: ' + e.message);
  }
}

const existing = index.records.find((r) => r && r.dossier_id === dossier.dossier_id);
if (existing) {
  existing.status = dossier.status || existing.status || 'active';
  existing.updated_at = now;
  existing.route_id = dossier.route_id || existing.route_id || null;
  existing.source_workflow = 'WF-001 Dossier Create Canonical';
} else {
  index.records.push({
    dossier_id: dossier.dossier_id,
    status: dossier.status || 'active',
    created_at: dossier.created_at || now,
    updated_at: now,
    route_id: dossier.route_id || null,
    source_workflow: 'WF-001 Dossier Create Canonical'
  });
}
index.last_updated = now;
fs.writeFileSync(indexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    ...$json,
    persistence: {
      wf: 'WF-001',
      dossier_path: dossierPath,
      dossier_index_path: indexPath,
      dossier_index_records: index.records.length,
      persisted_at: now
    },
    dossier_write: {
      mutation_type: 'create',
      target: 'dossier',
      timestamp: now,
      writer_id: 'WF-001',
      instance_id: dossier.dossier_id,
      audit_entry: 'dossier-create from WF-001'
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_workflow_execution',
      workflow_id: 'WF-001',
      dossier_id: $json.dossier_record.dossier_id,
      route_id: $json.dossier_record.route_id,
      execution_timestamp: new Date().toISOString(),
      status: 'COMPLETED'
    }
  }
}];

if ($json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-001',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-001-COMP-' + Date.now(),
      artifact_family: 'dossier_creation_packet',
      schema_version: '1.0.0',
      producer_workflow: 'WF-001',
      dossier_ref: $json.dossier_record.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        dossier_id: $json.dossier_record.dossier_id,
        route_id: $json.dossier_record.route_id,
        next_workflow: 'WF-010',
        route_to_wf900: 'WF-900'
      }
    }
  }
}];

if (!$json.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-001',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: $json.validation_error || 'Dossier creation failed',
    failure_packet: { instance_id: 'WF-001-ERR-' + Date.now(), artifact_family: 'intake_error', error: $json.validation_error }
  }
}];
